#include <stdio.h>

#define MAX 1000 // Define maximum size for the array

int deque[MAX];  // Array for deque
int front = 0, back = 0;

void push_back(int value) {
    deque[back++] = value;
}

void pop_back() {
    if (back > front) {
        back--;
    }
}

void pop_front() {
    if (back > front) {
        front++;
    }
}

int front_value() {
    return deque[front];
}

int is_empty() {
    return front == back;
}

int back_value() {
    return deque[back - 1];
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int N, X;
        scanf("%d %d", &N, &X);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }

        front = back = 0;  // Reset deque for each test case

        for (int i = 0; i < N; i++) {
            int x = A[i];

            // Remove elements from the deque's back while they are smaller than or equal to x
            while (!is_empty() && A[back_value()] <= x) {
                pop_back();
            }

            // Push current index to the back of the deque
            push_back(i);

            // When the window size is achieved, start printing results
            if (i >= X - 1) {
                // Remove elements that are outside of the window
                if (i >= X && front_value() == i - X) {
                    pop_front();
                }

                // Print the maximum element in the current window
                printf("%d ", A[front_value()]);
            }
        }
        printf("\n");
    }
    return 0;
}

