function solveSlidingWindowMax(input) {
    // Split input into lines and parse
    const lines = input.trim().split("\n");
    let t = parseInt(lines[0].trim());
    let outputLines = [];
    let lineIndex = 1;

    for (let i = 0; i < t; i++) {
        let [n, x] = lines[lineIndex++].trim().split(" ").map(Number);
        let arr = lines[lineIndex++].trim().split(" ").map(Number);

        let deque = []; // will store indices
        let res = [];

        // Process first window
        for (let j = 0; j < x; j++) {
            while (deque.length > 0 && arr[j] >= arr[deque[deque.length - 1]]) {
                deque.pop();
            }
            deque.push(j);
        }

        // For remaining elements
        for (let j = x; j < n; j++) {
            // The front of the deque is the largest element of the previous window
            res.push(arr[deque[0]]);

            // Remove indices that are out of the current window
            while (deque.length > 0 && deque[0] <= j - x) {
                deque.shift();
            }

            // Remove indices whose corresponding values are less than arr[j]
            while (deque.length > 0 && arr[j] >= arr[deque[deque.length - 1]]) {
                deque.pop();
            }

            deque.push(j);
        }
        // Add max for the last window
        res.push(arr[deque[0]]);

        outputLines.push(res.join(" "));
    }

    return outputLines.join("\n");
}
